// Seed 30 simple stdin/stdout problems. Each problem's expected outputs are
// generated by a reference `solve` function, so test cases are correct by
// construction. Upserts by slug (safe to re-run).
//
//   node scripts/seed-simple-problems.mjs
//
// Reads YIPDB_MONGODB_URI from the environment (or .env.local). On Windows it
// applies the same mongodb+srv SRV workaround as scripts/seed-problems.mjs.

import { MongoClient } from "mongodb";
import { readFileSync } from "node:fs";
import dns from "node:dns";
import { promisify } from "node:util";
import { execSync } from "node:child_process";

// --- Windows SRV workaround (mirrors app/lib/mongo/ensureDns.ts) -----------
const PUBLIC_FALLBACKS = ["1.1.1.1", "8.8.8.8"];
const isIPv4 = (s) => /^\d{1,3}(\.\d{1,3}){3}$/.test(s);
function osDnsServers() {
	try {
		const out = execSync(
			'powershell -NoProfile -Command "(Get-DnsClientServerAddress -AddressFamily IPv4).ServerAddresses"',
			{ encoding: "utf8", timeout: 5000 }
		);
		return out.split(/\r?\n/).map((s) => s.trim()).filter((s) => isIPv4(s) && s !== "127.0.0.1");
	} catch {
		return [];
	}
}
function probe(server, srvName, timeoutMs) {
	return new Promise((resolve) => {
		const r = new dns.Resolver({ timeout: timeoutMs, tries: 1 });
		r.setServers([server]);
		let settled = false;
		const done = (ok) => { if (!settled) { settled = true; resolve(ok); } };
		const t = setTimeout(() => done(false), timeoutMs + 250);
		r.resolveSrv(srvName, (err, addrs) => { clearTimeout(t); done(!err && Array.isArray(addrs) && addrs.length > 0); });
	});
}
async function findWorkingServers(srvName) {
	const candidates = [...new Set([...dns.getServers(), ...osDnsServers(), ...PUBLIC_FALLBACKS].filter((s) => isIPv4(s) && s !== "127.0.0.1"))];
	const results = await Promise.all(candidates.map(async (s) => ({ s, ok: await probe(s, srvName, 2000) })));
	return results.filter((r) => r.ok).map((r) => r.s);
}
async function resolveMongoUri(uri) {
	dns.setDefaultResultOrder("ipv4first");
	if (process.platform !== "win32") return uri;
	if (!uri.startsWith("mongodb+srv://")) return uri;
	const parsed = uri.match(/^mongodb\+srv:\/\/(?:([^@]+)@)?([^/?]+)([^?]*)?(?:\?(.*))?$/i);
	if (!parsed) return uri;
	const creds = parsed[1] ?? "", host = parsed[2], path = parsed[3] ?? "", query = parsed[4] ?? "";
	const srvName = `_mongodb._tcp.${host}`;
	try {
		const servers = await findWorkingServers(srvName);
		if (servers.length === 0) return uri;
		const resolver = new dns.Resolver();
		resolver.setServers(servers);
		const resolveSrv = promisify(resolver.resolveSrv.bind(resolver));
		const resolveTxt = promisify(resolver.resolveTxt.bind(resolver));
		const srv = await resolveSrv(srvName);
		if (!srv.length) return uri;
		const hosts = srv.map((r) => `${r.name}:${r.port}`).join(",");
		let txtParams = "";
		try { const txt = await resolveTxt(host); txtParams = txt.map((c) => c.join("")).join("&"); } catch {}
		const params = new URLSearchParams(txtParams);
		if (!params.has("tls") && !params.has("ssl")) params.set("tls", "true");
		for (const [k, v] of new URLSearchParams(query)) params.set(k, v);
		return `mongodb://${creds ? creds + "@" : ""}${hosts}/${path.replace(/^\//, "")}?${params.toString()}`;
	} catch {
		return uri;
	}
}

function loadEnv() {
	if (process.env.YIPDB_MONGODB_URI) return;
	try {
		const raw = readFileSync(new URL("../.env.local", import.meta.url), "utf-8");
		for (const line of raw.split("\n")) {
			const m = line.match(/^\s*([A-Z0-9_]+)\s*=\s*(.*)\s*$/);
			if (m && !process.env[m[1]]) process.env[m[1]] = m[2].replace(/^["']|["']$/g, "");
		}
	} catch {}
}

// --- Problem definitions ----------------------------------------------------
// Each: { slug, title, description, difficulty, visible, inputs[], solve(stdin) }
// `solve` receives stdin (trailing newline trimmed) and returns the exact stdout
// (without a trailing newline). Expected outputs are generated from it.
const nums = (s) => s.trim().split(/\s+/).map(Number);
const lines = (s) => s.replace(/\r/g, "").split("\n");

const P = [
	{ slug: "s-hello-world", title: "Hello, World!", difficulty: "easy", visible: 1,
		description: "# Hello, World!\n\n`Hello, World!` 를 출력하세요. (입력 없음)",
		inputs: [""], solve: () => "Hello, World!" },

	{ slug: "s-echo-line", title: "입력 그대로 출력", difficulty: "easy", visible: 2,
		description: "# 입력 그대로 출력\n\n한 줄이 주어집니다. 그대로 출력하세요.",
		inputs: ["hello", "coding is fun", "12345"], solve: (s) => s },

	{ slug: "s-sum-two", title: "두 수의 합", difficulty: "easy", visible: 2,
		description: "# 두 수의 합\n\n두 정수 `a b`가 주어집니다. `a + b`를 출력하세요.",
		inputs: ["3 5", "10 20", "-4 9", "1000 2500"], solve: (s) => { const [a, b] = nums(s); return String(a + b); } },

	{ slug: "s-sub-two", title: "두 수의 차", difficulty: "easy", visible: 2,
		description: "# 두 수의 차\n\n두 정수 `a b`가 주어집니다. `a - b`를 출력하세요.",
		inputs: ["10 3", "5 8", "100 50", "-2 -7"], solve: (s) => { const [a, b] = nums(s); return String(a - b); } },

	{ slug: "s-mul-two", title: "두 수의 곱", difficulty: "easy", visible: 2,
		description: "# 두 수의 곱\n\n두 정수 `a b`가 주어집니다. `a * b`를 출력하세요.",
		inputs: ["3 4", "7 6", "0 99", "12 12"], solve: (s) => { const [a, b] = nums(s); return String(a * b); } },

	{ slug: "s-floor-div", title: "몫 구하기", difficulty: "easy", visible: 2,
		description: "# 몫 구하기\n\n두 양의 정수 `a b`가 주어집니다. `a`를 `b`로 나눈 몫을 출력하세요.",
		inputs: ["10 3", "20 4", "7 2", "100 9"], solve: (s) => { const [a, b] = nums(s); return String(Math.floor(a / b)); } },

	{ slug: "s-remainder", title: "나머지 구하기", difficulty: "easy", visible: 2,
		description: "# 나머지 구하기\n\n두 양의 정수 `a b`가 주어집니다. `a`를 `b`로 나눈 나머지를 출력하세요.",
		inputs: ["10 3", "20 4", "7 5", "100 9"], solve: (s) => { const [a, b] = nums(s); return String(a % b); } },

	{ slug: "s-sum-three", title: "세 수의 합", difficulty: "easy", visible: 2,
		description: "# 세 수의 합\n\n세 정수 `a b c`가 주어집니다. 합을 출력하세요.",
		inputs: ["1 2 3", "10 20 30", "-5 5 0", "7 7 7"], solve: (s) => String(nums(s).reduce((a, b) => a + b, 0)) },

	{ slug: "s-max-two", title: "두 수 중 큰 값", difficulty: "easy", visible: 2,
		description: "# 두 수 중 큰 값\n\n두 정수 `a b`가 주어집니다. 더 큰 값을 출력하세요.",
		inputs: ["3 5", "10 2", "-4 -9", "7 7"], solve: (s) => { const [a, b] = nums(s); return String(Math.max(a, b)); } },

	{ slug: "s-min-two", title: "두 수 중 작은 값", difficulty: "easy", visible: 2,
		description: "# 두 수 중 작은 값\n\n두 정수 `a b`가 주어집니다. 더 작은 값을 출력하세요.",
		inputs: ["3 5", "10 2", "-4 -9", "7 7"], solve: (s) => { const [a, b] = nums(s); return String(Math.min(a, b)); } },

	{ slug: "s-abs", title: "절댓값", difficulty: "easy", visible: 2,
		description: "# 절댓값\n\n정수 `n`이 주어집니다. 절댓값을 출력하세요.",
		inputs: ["-7", "5", "0", "-100"], solve: (s) => String(Math.abs(Number(s.trim()))) },

	{ slug: "s-square", title: "제곱", difficulty: "easy", visible: 2,
		description: "# 제곱\n\n정수 `n`이 주어집니다. `n`의 제곱을 출력하세요.",
		inputs: ["3", "10", "-4", "0"], solve: (s) => { const n = Number(s.trim()); return String(n * n); } },

	{ slug: "s-even-odd", title: "짝수 홀수", difficulty: "easy", visible: 2,
		description: "# 짝수 홀수\n\n정수 `n`이 주어집니다. 짝수면 `even`, 홀수면 `odd`를 출력하세요.",
		inputs: ["4", "7", "0", "13"], solve: (s) => (Math.abs(Number(s.trim())) % 2 === 0 ? "even" : "odd") },

	{ slug: "s-sign", title: "부호 판별", difficulty: "easy", visible: 2,
		description: "# 부호 판별\n\n정수 `n`이 주어집니다. 양수면 `positive`, 음수면 `negative`, 0이면 `zero`를 출력하세요.",
		inputs: ["5", "-3", "0", "100"], solve: (s) => { const n = Number(s.trim()); return n > 0 ? "positive" : n < 0 ? "negative" : "zero"; } },

	{ slug: "s-sum-1-to-n", title: "1부터 n까지의 합", difficulty: "easy", visible: 2,
		description: "# 1부터 n까지의 합\n\n양의 정수 `n`이 주어집니다. `1 + 2 + ... + n`을 출력하세요.",
		inputs: ["5", "10", "1", "100"], solve: (s) => { const n = Number(s.trim()); return String((n * (n + 1)) / 2); } },

	{ slug: "s-factorial", title: "팩토리얼", difficulty: "easy", visible: 2,
		description: "# 팩토리얼\n\n정수 `n` (0 ≤ n ≤ 12)이 주어집니다. `n!`을 출력하세요.",
		inputs: ["5", "0", "3", "10"], solve: (s) => { let n = Number(s.trim()), r = 1; for (let i = 2; i <= n; i++) r *= i; return String(r); } },

	{ slug: "s-power-of-two", title: "2의 거듭제곱", difficulty: "easy", visible: 2,
		description: "# 2의 거듭제곱\n\n정수 `n` (0 ≤ n ≤ 30)이 주어집니다. `2^n`을 출력하세요.",
		inputs: ["3", "0", "10", "20"], solve: (s) => String(2 ** Number(s.trim())) },

	{ slug: "s-countdown", title: "카운트다운", difficulty: "easy", visible: 2,
		description: "# 카운트다운\n\n양의 정수 `n`이 주어집니다. `n`부터 `1`까지 한 줄에 하나씩 출력하세요.",
		inputs: ["3", "5", "1", "7"], solve: (s) => { const n = Number(s.trim()); const a = []; for (let i = n; i >= 1; i--) a.push(i); return a.join("\n"); } },

	{ slug: "s-gugudan", title: "구구단", difficulty: "easy", visible: 2,
		description: "# 구구단\n\n정수 `n` (1 ≤ n ≤ 9)이 주어집니다. `n`단을 `n x i = 결과` 형식으로 9줄 출력하세요.\n\n예: `2 x 1 = 2`",
		inputs: ["2", "5", "9", "1"], solve: (s) => { const n = Number(s.trim()); const a = []; for (let i = 1; i <= 9; i++) a.push(`${n} x ${i} = ${n * i}`); return a.join("\n"); } },

	{ slug: "s-sum-array", title: "배열의 합", difficulty: "easy", visible: 2,
		description: "# 배열의 합\n\n첫 줄에 개수 `n`, 둘째 줄에 `n`개의 정수가 주어집니다. 합을 출력하세요.",
		inputs: ["5\n1 2 3 4 5", "3\n10 20 30", "1\n42", "4\n-1 -2 3 4"], solve: (s) => { const arr = nums(lines(s)[1]); return String(arr.reduce((a, b) => a + b, 0)); } },

	{ slug: "s-max-array", title: "배열의 최댓값", difficulty: "easy", visible: 2,
		description: "# 배열의 최댓값\n\n첫 줄에 개수 `n`, 둘째 줄에 `n`개의 정수가 주어집니다. 최댓값을 출력하세요.",
		inputs: ["5\n3 1 4 1 5", "3\n10 20 5", "1\n7", "4\n-3 -1 -7 -2"], solve: (s) => String(Math.max(...nums(lines(s)[1]))) },

	{ slug: "s-count-even", title: "짝수의 개수", difficulty: "easy", visible: 2,
		description: "# 짝수의 개수\n\n첫 줄에 개수 `n`, 둘째 줄에 `n`개의 정수가 주어집니다. 짝수의 개수를 출력하세요.",
		inputs: ["5\n1 2 3 4 5", "3\n2 4 6", "4\n1 3 5 7", "6\n10 11 12 13 14 15"], solve: (s) => String(nums(lines(s)[1]).filter((x) => x % 2 === 0).length) },

	{ slug: "s-reverse-string", title: "문자열 뒤집기", difficulty: "easy", visible: 2,
		description: "# 문자열 뒤집기\n\n한 줄의 문자열이 주어집니다. 뒤집어서 출력하세요.",
		inputs: ["hello", "abcde", "racecar", "12345"], solve: (s) => s.split("").reverse().join("") },

	{ slug: "s-string-length", title: "문자열 길이", difficulty: "easy", visible: 2,
		description: "# 문자열 길이\n\n한 줄의 문자열(공백 없음)이 주어집니다. 길이를 출력하세요.",
		inputs: ["hello", "a", "programming", "12345678"], solve: (s) => String(s.length) },

	{ slug: "s-to-upper", title: "대문자로 변환", difficulty: "easy", visible: 2,
		description: "# 대문자로 변환\n\n한 줄의 문자열이 주어집니다. 모두 대문자로 바꿔 출력하세요.",
		inputs: ["hello", "Coding", "abc def", "Mix123"], solve: (s) => s.toUpperCase() },

	{ slug: "s-count-vowels", title: "모음의 개수", difficulty: "easy", visible: 2,
		description: "# 모음의 개수\n\n한 줄의 문자열이 주어집니다. 모음(a, e, i, o, u)의 개수를 출력하세요. (대소문자 모두)",
		inputs: ["hello", "programming", "xyz", "AEIOU"], solve: (s) => String([...s].filter((c) => "aeiouAEIOU".includes(c)).length) },

	{ slug: "s-palindrome", title: "회문 판별", difficulty: "easy", visible: 2,
		description: "# 회문 판별\n\n한 줄의 문자열(공백 없음)이 주어집니다. 거꾸로 읽어도 같으면 `yes`, 아니면 `no`를 출력하세요.",
		inputs: ["racecar", "hello", "level", "abcba"], solve: (s) => (s === s.split("").reverse().join("") ? "yes" : "no") },

	{ slug: "s-fib-nth", title: "n번째 피보나치 수", difficulty: "easy", visible: 2,
		description: "# n번째 피보나치 수\n\n정수 `n` (1 ≤ n ≤ 30)이 주어집니다. `n`번째 피보나치 수를 출력하세요. (1, 1, 2, 3, 5, ...)",
		inputs: ["1", "2", "7", "10"], solve: (s) => { const n = Number(s.trim()); let a = 1, b = 1; for (let i = 3; i <= n; i++) { [a, b] = [b, a + b]; } return String(n <= 2 ? 1 : b); } },

	{ slug: "s-gcd", title: "최대공약수", difficulty: "easy", visible: 2,
		description: "# 최대공약수\n\n두 양의 정수 `a b`가 주어집니다. 최대공약수를 출력하세요.",
		inputs: ["12 18", "5 7", "100 40", "9 3"], solve: (s) => { let [a, b] = nums(s); while (b) { [a, b] = [b, a % b]; } return String(a); } },

	{ slug: "s-sum-digits", title: "각 자리 숫자의 합", difficulty: "easy", visible: 2,
		description: "# 각 자리 숫자의 합\n\n0 이상의 정수 `n`이 주어집니다. 각 자리 숫자의 합을 출력하세요.",
		inputs: ["123", "9999", "0", "504"], solve: (s) => String(s.trim().split("").reduce((a, c) => a + Number(c), 0)) },
];

function toProblem(p, now) {
	const testcases = p.inputs.map((stdin, i) => {
		const trimmed = stdin.replace(/\n$/, "");
		const norm = stdin === "" ? "" : trimmed + "\n";
		return { stdin: norm, expectedOutput: p.solve(trimmed) + "\n", hidden: i >= p.visible };
	});
	return {
		slug: p.slug,
		title: p.title,
		description: p.description,
		difficulty: p.difficulty,
		languages: ["python", "javascript", "cpp", "java", "go"],
		starterCode: {},
		testcases,
		timeLimit: 5,
		memoryLimit: 256000,
		createdBy: "seed",
		updatedAt: now,
	};
}

loadEnv();
const uri = process.env.YIPDB_MONGODB_URI;
if (!uri) { console.error("YIPDB_MONGODB_URI is not set"); process.exit(1); }

const client = new MongoClient(await resolveMongoUri(uri));
try {
	await client.connect();
	const col = client.db("yipDB").collection("problems");
	await col.createIndex({ slug: 1 }, { unique: true });
	const now = new Date();
	let n = 0;
	for (const def of P) {
		const doc = toProblem(def, now);
		await col.updateOne(
			{ slug: doc.slug },
			{ $set: doc, $setOnInsert: { createdAt: now } },
			{ upsert: true }
		);
		n++;
	}
	console.log(`Seeded ${n} simple problems.`);
} finally {
	await client.close();
}
